// ---- Terrain (src/world/terrain.js) — sim coords in/out; real-meter math inside
class Terrain {
  constructor(levelData /* LEVEL from config/level.js */, bus, startWorldScale /*=0.1*/)
  standSimY(x:number, z:number): number             // highest floor containing point (sim); 0 on base plane
  collide(ball: BallState): void                    // rigid-wall pushback + step-edge per-axis resolve; WRITES ball.standSimY (authoritative); emits EVT.BOUNCE (0.25s cd), EVT.DOOR_HINT
  clampCameraBoom(ballPos:Vector3, desiredCam:Vector3, out:Vector3): boolean // shorten boom to nearest blocking wall - CAM_WALL_MARGIN_K*r; true if clamped
  clampToBounds(ball: BallState): void              // failsafe AABB clamp to LEVEL_BOUNDS
  bandMaskAt(x:number, z:number): number            // 0 outside all zones
  interiorAt(x:number, z:number): 0|1
}
// ---- LevelSpawner (src/world/levelSpawner.js)
class LevelSpawner {
  constructor(levelData, terrain, store, hashes, instances /*Map id->pool*/, bus, catalog)
  update(ballPos, tierIndex, ballRadiusSim): void   // after spawner.update; also drains deferred ABSORB cleanup queue
  preload(ballPos): void;  reset(): void
  isRare(objIndex:number): boolean                  // valid during AND for one full frame after the ABSORB emit (deferred cleanup)
  forEachAliveRare(cb:(idx,x,y,z,r)=>void): void
  get rareTotal(): number;  get aliveCount(): number // ownership assert
}
// ---- RunStats (src/game/runStats.js)
class RunStats {
  constructor(bus, scaleMgr, rareProvider:{isRare,rareTotal}, worldSeed)
  addSimTime(s:number): void;  reset(): void
  get timeS(): number;  get score(): number
  static loadBest(): {bestTimeS,bestScore,bestRank,seed}|null
}
// ---- Bgm / Backdrop / TerrainMeshView
class Bgm { constructor(bus); setMuted(b); dispose() }
class TerrainMeshView { constructor(scene, levelData, bus, startWorldScale); dispose() } // self-maintains group scale/origin
class Backdrop { constructor(scene); update(camera); dispose() }
// ---- Changed signatures
new BallPhysics(terrain = null, bus = null)            // terrain null => stand=0 plane (v1 headless behavior)
BallPhysics.reset(radiusSim = SIM_RADIUS_MIN, x = 0, z = 0, standSimY = 0) // seeds _ySpring at standSimY+radiusSim
new Spawner(worldSeed, store, hashes, instances, bus, catalog, terrain = null)
new Environment(scene, camera, terrain = null)
new CameraRig(camera, bus, terrain = null)
cameraRig.celebrate(ballState): void                   // CELEBRATE orbit; reset() exits
effects.setRareProvider(fn): void
input.takeMuteToggle(): boolean
// ---- types.js additions
Intent    += { dash: boolean }                          // edge, one read
BallState += { dashGauge01: number, dashTimer: number, standSimY: number /* authoritative, terrain.collide-only writer */ }
GrowEvent += { dashGauge01: number }
Tier      += { reachable: boolean };  export MAX_REACHABLE_TIER (tiers.js)
// ---- New bus events (reused PAYLOADS, read-only)
'dash'      { gauge01:number }                          // ballPhysics -> camera kick, effects lines, sfx whoosh, hud zero
'dashReady' {}                                          // ballPhysics once per refill -> hud flash, sfx chime
'doorHint'  { openWidthReal:number }                    // terrain -> hud toast
'score'     { score,delta,combo,rare }                  // runStats -> hud, sfx(rare)
'time'      { timeS }                                   // runStats 10Hz -> hud
'goal'      { timeS,score,rank,trueRadius,absorbed,raresFound,rareTotal,seed } // runStats once -> main(CELEBRATE), screens(cache), sfx(fanfare), bgm(duck), effects(confetti)
// 'game:win' emitted by MAIN at celebration end; screens shows result from cached GOAL
